INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c800b98-87da-4392-80f8-cc8ac66f95be', $q$Cross-device sync$q$, $q$Start a design on web and continue on the iOS or Android app with projects synced via Creative Cloud.$q$, 9);
